export function broadcastToSession(sessionId: string, event: ChatWsEvent): void {
  const clients = sessionConnections.get(sessionId);
  if (!clients) return;
  const payload = JSON.stringify(event);
  for (const ws of clients) {
    if (ws.readyState === WebSocket.OPEN) {
      ws.send(payload);
    }
  }
}

export function attachChatWss(httpServer: HttpServer): void {
  const wss = new WebSocketServer({ noServer: true });

  httpServer.on('upgrade', (req: IncomingMessage, socket, head) => {
    const pathname = new URL(req.url ?? '', 'http://x').pathname;

    // Match /api/v1/agent_chat/<session_id>/ws
    const match = pathname.match(/^\/api\/v1\/agent_chat\/([^/]+)\/ws$/);
    if (!match) {
      // Don't destroy — ws_console or other handlers may match
      return;
    }

    const sessionId = match[1];
    const claims = parseToken(req);
    if (!claims) {
      socket.write('HTTP/1.1 401 Unauthorized\r\n\r\n');
      socket.destroy();
      return;
    }

    wss.handleUpgrade(req, socket, head, async (ws) => {
      // Validate session access
      const session = await getSession(sessionId, claims.tenantId);
      if (!session || session.actor_user_id !== claims.userId) {
        const errEvent: ChatWsEvent = {
          type: 'error',
          error_code: 'SESSION_NOT_FOUND',
          text: 'Session not found or access denied',
          correlation_id: 'system',
        };
        ws.send(JSON.stringify(errEvent));
        ws.close();
        return;
      }

      // Register connection
      if (!sessionConnections.has(sessionId)) {
        sessionConnections.set(sessionId, new Set());
      }
