 * Load ordered composition inputs for deterministic markdown reconstruction.
 * Scoped by tenant_id.
 */
export async function loadCompositionInputs(
  tenantId: string,
  documentRevisionId: string
): Promise<CompositionInput> {
  const conn = (await db.getConnection()) as PoolConnection;
  try {
    const revRows = normalizeQueryRows<DocumentRevisionRecord>(await conn.query(
      `SELECT document_revision_id, tenant_id, document_id, version_label,
              manifest_id, revision_status, author_role, created_at
       FROM document_revisions
       WHERE tenant_id = ? AND document_revision_id = ?`,
      [tenantId, documentRevisionId]
    ));
    if (!revRows || revRows.length === 0) {
      throw new Error(`DocCore: revision not found — ${documentRevisionId}`);
    }
    const revision = revRows[0] as DocumentRevisionRecord;

    const mRows = normalizeQueryRows<ManifestRecord>(await conn.query(
      `SELECT manifest_id, tenant_id, document_revision_id, composition_status,
              generated_checksum, created_at
       FROM manifests
       WHERE tenant_id = ? AND document_revision_id = ?`,
      [tenantId, documentRevisionId]
    ));
    if (!mRows || mRows.length === 0) {
