/**
 * Map HTTP method to required permission bit.
 */
function methodToBit(method: string): Permission {
    switch (method.toUpperCase()) {
        case 'DELETE': return PERMISSIONS.DELETE;
        case 'POST':
        case 'PUT':
        case 'PATCH':  return PERMISSIONS.WRITE;
        case 'GET':
        default:       return PERMISSIONS.READ;
    }
}

/**
 * checkAccess middleware factory.
 * Usage: router.use(checkAccess('portfolio', (req) => req.params.portfolioId))
 */
export function checkAccess(
    entityType: 'portfolio' | 'program' | 'project',
    getEntityId: (req: AuthenticatedRequest) => string
) {
    return async (req: AuthenticatedRequest, res: Response, next: NextFunction): Promise<void> => {
        if (!req.userId || !req.tenantId) {
            res.status(401).json({ error: 'Not authenticated' });
            return;
        }

        // System admin bypass
        if ((req as any).isSystemAdmin) { next(); return; }

        const entityId = getEntityId(req);
        if (!entityId) { res.status(400).json({ error: 'Entity ID missing' }); return; }

        const required = methodToBit(req.method);
        const conn = await db.getConnection();
        try {
            const mask = await resolveMask(req.userId, req.tenantId, entityType, entityId, conn);
            if ((mask & required) !== required) {
                res.status(403).json({
                    error: 'Insufficient RBAC Privileges',
                    detail: `Required permission bit ${required}, got mask ${mask}`,
                });
                return;
            }
            // Attach mask to request for downstream use (e.g., sync_enforcer)
            (req as any).permissionsMask = mask;
            next();
        } finally {
            conn.release();
        }
    };
}

