export type SettingsMap = Record<string, unknown>;

function safeJson(raw: unknown): SettingsMap {
    if (!raw) return {};
    if (typeof raw === 'object') return raw as SettingsMap;
    try { return JSON.parse(raw as string); } catch { return {}; }
}

/**
 * Deep-merge settings layers.
 * Higher layers (later in the array) win, UNLESS the lower layer has
 * `allow_lower_overwrites: false` set for a given key.
 */
function mergeLayers(...layers: SettingsMap[]): SettingsMap {
    const result: SettingsMap = {};
    for (const layer of layers) {
        for (const [key, value] of Object.entries(layer)) {
            if (key === 'allow_lower_overwrites') continue; // meta-key, not a user setting
            result[key] = value;
        }
    }
    return result;
}

