function normalizeVersionLabel(label: string): string {
  const trimmed = label.trim() || 'revision';
  if (trimmed.length <= MAX_VERSION_LABEL_LENGTH) return trimmed;

  const suffix = `-${createHash('sha1').update(trimmed).digest('hex').substring(0, 8)}`;
  const maxStemLength = MAX_VERSION_LABEL_LENGTH - suffix.length;
  const stem = trimmed.slice(0, maxStemLength).replace(/-+$/g, '');
  return `${stem}${suffix}`;
}
