function deriveDocumentTitleFromContent(contentMd: string, fallback: string): string {
  const content = String(contentMd ?? '').replace(/\r\n/g, '\n');
  const lines = content.split('\n').map((line) => line.trim()).filter(Boolean);
  for (const line of lines) {
    const headingMatch = line.match(/^#{1,6}\s+(.+?)\s*$/);
    if (headingMatch) {
      return headingMatch[1].trim();
    }
  }
  return fallback;
}

function deriveDocumentPrimaryPdc(pdcAreas: string[]): string {
  return pdcAreas.find((area) => area.trim().length > 0) ?? 'Uncategorized';
