    private killWorker(blueprint: AgentBlueprint): void {
        const agentId = blueprint.agent_id;
        const workerProcess = activeWorkers.get(agentId);

        if (workerProcess) {
            logger.info({ agentId, pid: workerProcess.pid }, 'Attempting to kill worker');
            // Gracefully terminate the process
            // On POSIX, 'SIGTERM' is the default for process.kill()
            // On Windows, it's typically more forceful
            try {
                process.kill(workerProcess.pid!, 'SIGTERM'); // Send SIGTERM
                activeWorkers.delete(agentId);
                activeWorkerMetadata.delete(agentId);
                logger.info({ agentId, pid: workerProcess.pid }, 'Worker sent SIGTERM.');
            } catch (error) {
                logger.error({ err: error, agentId, pid: workerProcess.pid }, 'Failed to send SIGTERM to worker');
                // If SIGTERM fails, try more forcefully or just remove from map if already dead
                activeWorkers.delete(agentId);
                activeWorkerMetadata.delete(agentId);
            }
        } else {
            logger.warn({ agentId }, 'No active worker found for agent.');
        }
    }
}
