  | 'TYPE_MISMATCH'
  | 'POLICY_DENIED'
  | 'AGENT_NOT_FOUND';

const TASK_TYPE_MAP: Record<AssignmentType, string[]> = {
  TASK: ['feature', 'task'],
  TEST: ['test'],
  BUG:  ['bug'],
};

export async function applyAssignment(params: {
  agentId: string;
  tenantId: string;
  actorUserId: string;
  correlationId: string;
  assignmentType: AssignmentType;
  workItemId: string;
  notes?: string;
}): Promise<AssignmentResult> {
  let conn;
  try {
    conn = await db.getConnection();

    // Verify agent exists in tenant scope
    const agentRows = await conn.query(
      'SELECT id FROM agents WHERE id = ?,
      [params.agentId, params.tenantId]
    );
    if (!agentRows || agentRows.length === 0) return 'AGENT_NOT_FOUND';

    // Fetch the work item
    const taskRows = await conn.query(
      'SELECT task_uid, type FROM tasks WHERE task_uid = ? AND tenant_id = ?',
      [params.workItemId, params.tenantId]
    );
    if (!taskRows || taskRows.length === 0) return 'NOT_FOUND';

    const task = taskRows[0];
