        const required = methodToBit(req.method);
        const conn = await db.getConnection();
        try {
            const mask = await resolveMask(req.userId, req.tenantId, entityType, entityId, conn);
            if ((mask & required) !== required) {
                res.status(403).json({
                    error: 'Insufficient RBAC Privileges',
                    detail: `Required permission bit ${required}, got mask ${mask}`,
                });
                return;
            }
            // Attach mask to request for downstream use (e.g., sync_enforcer)
            (req as any).permissionsMask = mask;
            next();
        } finally {
            conn.release();
        }
    };
}

/**
 * hasPermission — utility for inline checks (e.g. in sync_enforcer)
 */
export function hasPermission(mask: number, permission: Permission): boolean {
    return (mask & permission) === permission;
}
