    package: pkg,
    cached_at: new Date(),
    source_timestamps: new Map(sourceTimestamps),
  });
}

/**
 * Removes cache entries whose source nodes include the given source_ref.
 * Returns count of invalidated entries.
 */
export function invalidateBySource(source_ref: string, tenant_id: string): number {
  let count = 0;
  for (const [key, entry] of cache) {
    if (!key.startsWith(`${tenant_id}:`)) continue;
    const nodeIds = [...entry.source_timestamps.keys()];
    if (nodeIds.includes(source_ref)) {
      cache.delete(key);
      count++;
    }
  }
  return count;
}

