+import { Router, Request, Response } from 'express';
+import { AgentChatService } from '../../services/agent_chat_service';
+
+export function createAgentChatRouter(chatService: AgentChatService): Router {
+  const router = Router({ mergeParams: true });
+
+  // POST /:agent_id/chat/messages
+  router.post('/messages', async (req: Request, res: Response) => {
+    try {
+      const claims = (req as any).jwtClaims;
+      const agentId = req.params.agent_id as string;
+      const { content } = req.body;
+
+      if (!content || typeof content !== 'string' || content.trim().length === 0) {
+        return res.status(400).json({ success: false, error: 'content is required' });
+      }
+      if (content.length > 4096) {
+        return res.status(400).json({ success: false, error: 'content exceeds 4096 chars' });
+      }
+
+      const msg = await chatService.sendMessage(claims.tenant_id, agentId, content.trim());
+      return res.status(201).json({ success: true, data: msg });
+    } catch (err) {
+      console.error('[agent_chat_routes] send error:', err);
+      return res.status(500).json({ success: false, error: 'Internal server error' });
+    }
+  });
+
+  // GET /:agent_id/chat/stream  (Server-Sent Events)
+  router.get('/stream', (req: Request, res: Response) => {
+    const claims = (req as any).jwtClaims;
+    const agentId = req.params.agent_id as string;
+
+    res.setHeader('Content-Type', 'text/event-stream');
+    res.setHeader('Cache-Control', 'no-cache');
+    res.setHeader('Connection', 'keep-alive');
+    res.flushHeaders();
+
+    const unsubscribe = chatService.subscribe(claims.tenant_id, agentId, (msg) => {
+      res.write(`data: ${JSON.stringify(msg)}\n\n`);
+    });
+
+    // Send a keep-alive comment every 30s
+    const keepAlive = setInterval(() => res.write(': keep-alive\n\n'), 30_000);
+
+    req.on('close', () => {
+      clearInterval(keepAlive);
+      unsubscribe();
+    });
+  });
+
+  return router;
+}
