import { runtime } from '../api/container_manager';
import logger from '../utils/logger';

export class WarmPoolManager {
    private static pool: string[] = [];

    static async initialize(poolSize: number = 3): Promise<void> {
        const tasks = Array.from({ length: poolSize }, () => WarmPoolManager.createWarmContainer());
        const ids = await Promise.all(tasks);
        WarmPoolManager.pool.push(...ids);
        logger.info({ count: WarmPoolManager.pool.length }, '[WarmPool] Initialized with containers');
    }

    private static async createWarmContainer(): Promise<string> {
        const container = await runtime.createContainer({
            Image: 'agenthub/worker-bee:latest',
            Tty: false,
            HostConfig: { AutoRemove: false },
        });
        await container.start();
        return container.id;
    }

    static async claimContainer(tenantId: string, projectId: string): Promise<string | null> {
        if (WarmPoolManager.pool.length === 0) {
            return null;
        }
        const containerId = WarmPoolManager.pool.pop()!;
        await WarmPoolManager.resetWorkspace(containerId);
        const networkName = 'agenthub_net_' + tenantId + '_' + projectId;
        try {
            const network = runtime.getNetwork(networkName);
            await network.connect({ Container: containerId });
        } catch (e: any) {
            logger.error({ err: e }, '[WarmPool] Failed to connect container to network');
        }
        // Replenish asynchronously
        WarmPoolManager.createWarmContainer()
            .then(id => WarmPoolManager.pool.push(id))
            .catch(err => logger.error({ err }, '[WarmPool] Replenish failed'));
        return containerId;
    }

    private static async resetWorkspace(containerId: string): Promise<void> {
        const container = runtime.getContainer(containerId);
        const exec = await container.exec({
            Cmd: ['sh', '-c', 'rm -rf /home/agenthub/workspace/* && git init /home/agenthub/workspace'],
            AttachStdout: true,
            AttachStderr: true,
        });
        await new Promise<void>((resolve, reject) => {
            exec.start({ hijack: true, stdin: false }, (err: any, stream: any) => {
                if (err) return reject(err);
                if (!stream) return resolve();
                stream.on('end', resolve);
                stream.on('error', reject);
            });
        });
    }
}
