      conn = await db.getConnection();

      // Atomically lock the task to `testing`.  Use a conditional UPDATE so
      // only tasks still in `verifying` are locked (prevents races).
      const updateResult = await conn.query(
        `UPDATE tasks SET status = 'testing', version = version + 1
         WHERE task_id = ? AND tenant_id = ? AND status = 'verifying'`,
        [task_id, tenant_id]
      );

      if ((updateResult.affectedRows ?? 0) === 0) {
