// ---------------------------------------------------------------------------
// withTransaction — wraps a callback in a MariaDB transaction.
// Rolls back on error; releases the connection in all cases.
// ---------------------------------------------------------------------------

/**
 * Executes `fn` inside a MariaDB transaction obtained from the pool.
 * On error the transaction is rolled back before the error is rethrown.
 */
export async function withTransaction<T>(
  fn: (trx: PoolConnection) => Promise<T>
): Promise<T> {
  const conn = (await db.getConnection()) as PoolConnection;
  try {
    await conn.beginTransaction();
    const result = await fn(conn);
    await conn.commit();
    return result;
  } catch (err) {
    try {
      await conn.rollback();
    } catch (rbErr) {
      logger.error({ err: rbErr }, '[DocCoreRepository] rollback failed');
    }
    throw err;
  } finally {
    conn.release?.();
  }
}

