/**
 * Thrown when an access policy check fails.
 * Produces a doccore_access_denied error payload per o4701 §11.0 Table 11.0.1.
 */
export class DocCoreAccessError extends Error {
    public readonly payload: DocCoreErrorPayload;
    public readonly httpStatus: number;

