+
+type LabelValue = string | number | boolean | null | undefined;
+type Labels = Record<string, LabelValue>;
+type MetricType = 'counter' | 'gauge';
+
+interface MetricSample {
+  labels?: Labels;
+  value: number;
+}
+
+interface MetricFamily {
+  name: string;
+  help: string;
+  type: MetricType;
+  samples: MetricSample[];
+}
+
+class VectorMetric {
+  private samples = new Map<string, { labels: Labels; value: number }>();
+
+  constructor(
+    public readonly name: string,
+    public readonly help: string,
+    public readonly type: MetricType
+  ) {}
+
+  public set(labels: Labels, value: number): void {
+    const key = this.labelKey(labels);
+    this.samples.set(key, { labels, value });
+  }
+
+  public inc(labels: Labels, by: number = 1): void {
+    const key = this.labelKey(labels);
+    const existing = this.samples.get(key);
+    if (existing) {
+      existing.value += by;
+      return;
+    }
+    this.samples.set(key, { labels, value: by });
+  }
+
+  public collect(): MetricFamily {
+    return {
+      name: this.name,
+      help: this.help,
+      type: this.type,
+      samples: Array.from(this.samples.values()).map((sample) => ({
+        labels: sample.labels,
+        value: sample.value,
+      })),
+    };
+  }
+
+  private labelKey(labels: Labels): string {
+    return JSON.stringify(
+      Object.keys(labels)
+        .sort()
+        .reduce<Record<string, LabelValue>>((acc, key) => {
+          acc[key] = labels[key];
+          return acc;
+        }, {})
+    );
+  }
+}
