function parsePrometheusMetricLines(body: string, metricName: string): Array<{ labels: MetricLabels; value: number }> {
  const rows: Array<{ labels: MetricLabels; value: number }> = [];
  const prefix = `${metricName}`;

  for (const line of body.split('\n')) {
    if (!line || line.startsWith('#') || !line.startsWith(prefix)) {
      continue;
    }

    const match = line.match(/^([a-zA-Z_:][a-zA-Z0-9_:]*)(\{([^}]*)\})?\s+([-+]?[\d.eE]+)$/);
    if (!match) {
      continue;
    }

    const labels: MetricLabels = {};
    const labelText = match[3] || '';
    if (labelText) {
      const parts = labelText.match(/(?:[^,"]+|"[^"]*")+/g) || [];
      for (const part of parts) {
        const eqIndex = part.indexOf('=');
        if (eqIndex === -1) continue;
        const key = part.slice(0, eqIndex).trim();
        const rawValue = part.slice(eqIndex + 1).trim();
        labels[key] = rawValue.replace(/^"/, '').replace(/"$/, '').replace(/\\"/g, '"');
      }
    }

    rows.push({
      labels,
      value: Number(match[4]),
    });
  }

