+import { MetadataValidator } from '../../services/doccore/doccore_metadata_validator';
+import { createRevision } from '../../services/doccore/doccore_revision_service';
+
+const router = Router();
+const policy = new AccessPolicyAdapter();
+const validator = new MetadataValidator();
+
+// ---------------------------------------------------------------------------
+// Response envelope — matches the pattern used across AgentHub routes
+// ---------------------------------------------------------------------------
+
+function envelope(ok: boolean, data: unknown, error: string | null) {
+  return { ok, data, error, server_time: new Date().toISOString() };
+}
+
+// ---------------------------------------------------------------------------
+// POST /api/v1/doccore/revisions
+// ---------------------------------------------------------------------------
+
+/**
+ * Create a document revision.
+ *
+ * Auth: Bearer JWT with tenant_id + write-allowed role
+ * Body: RevisionPayload (validated by MetadataValidator)
+ *
+ * Returns 201 only after snapshot checksum is computed (synchronous — no
+ * fire-and-forget).
+ */
+router.post('/revisions', async (req, res) => {
+  const claims = (req as any).user ?? {};
+
+  // Access policy check
+  try {
+    policy.assertCanWrite(claims);
+  } catch (err: any) {
+    return res.status(403).json(
+      envelope(false, null, err.payload?.error_code ?? 'ACCESS_DENIED')
+    );
+  }
+
+  // Payload validation
+  let payload: any;
+  try {
+    payload = validator.validateRevisionPayload(req.body);
+  } catch (err: any) {
+    return res.status(422).json(
+      envelope(false, null, err.payload?.error_code ?? 'VALIDATION_ERROR')
+    );
+  }
+
+  // Service call — snapshot completes before 201 is returned
+  try {
+    const result = await createRevision({
+      tenantId: claims.tenant_id,
+      docId: payload.doc_id,
+      revisionSummary: payload.revision_summary,
+      manifestEntries: payload.manifest_entries,
+      actorId: claims.user_id ?? 'unknown',
+      dependencyEdges: payload.dependency_edges,
+    });
+    return res.status(201).json(envelope(true, result, null));
