const ENABLED_IN_STATES: Record<AgentMenuAction, AgentRuntimeState[]> = {
  START:            ['STOPPED', 'ERROR'],
  STOP:             ['RUNNING_IDLE', 'RUNNING_BUSY', 'ERROR'],
  CONFIGURATION:    ['STOPPED', 'RUNNING_IDLE', 'RUNNING_BUSY', 'ERROR'],
  ASSIGN_TASK:      ['RUNNING_IDLE', 'RUNNING_BUSY'],
  ASSIGN_TEST:      ['RUNNING_IDLE', 'RUNNING_BUSY'],
  ASSIGN_BUG:       ['RUNNING_IDLE', 'RUNNING_BUSY'],
  ASSIGN_ROLE:      ['STOPPED', 'RUNNING_IDLE', 'ERROR'],
  START_CHAT_SHELL: ['RUNNING_IDLE', 'RUNNING_BUSY'],
};

// Human-readable disabled reasons by action
const DISABLED_REASON: Record<AgentMenuAction, string> = {
  START:            'Agent is not in a startable state',
  STOP:             'Agent is not running',
  CONFIGURATION:    'Configuration is not accessible in this state',
  ASSIGN_TASK:      'Agent must be running to accept task assignments',
  ASSIGN_TEST:      'Agent must be running to accept test assignments',
  ASSIGN_BUG:       'Agent must be running to accept bug assignments',
  ASSIGN_ROLE:      'Role assignment not available in this state',
  START_CHAT_SHELL: 'Chat shell requires agent to be running',
};

function buildEntry(
  action: AgentMenuAction,
  state: AgentRuntimeState,
  overrideDisabled?: string
): ActionPolicyEntry {
  if (overrideDisabled) {
    return { enabled: false, reason: overrideDisabled };
  }
  const enabled = ENABLED_IN_STATES[action].includes(state);
  return {
    enabled,
    reason: enabled ? null : DISABLED_REASON[action],
  };
}

function inferRuntimeStateFromRegistry(row: any): AgentRuntimeState {
  const status = String(row?.status ?? '').toLowerCase();
  if (status === 'online') return 'RUNNING_IDLE';
  if (status === 'degraded') return 'RUNNING_BUSY';
  if (status === 'stopping') return 'STOPPING';
  if (status === 'starting') return 'STARTING';
  if (status === 'terminated' || status === 'offline') return 'OFFLINE';
  return 'OFFLINE';
}

