/**
 * Deletes T3 memory nodes older than max_age_hours for the given scope.
 * Returns the count of deleted rows. Writes one audit event per batch.
 */
export async function expireStaleTraces(scope: HlmmScope, maxAgeHours: number): Promise<number> {
  const conn = await pool.getConnection();
  let expiredCount = 0;
  try {
    const [result] = await conn.execute(
      `DELETE FROM hlmm_memory_nodes
       WHERE tenant_id = ? AND project_id = ? AND memory_tier = 'T3'
         AND freshness_marker < DATE_SUB(NOW(), INTERVAL ? HOUR)`,
      [scope.tenant_id, scope.project_id, maxAgeHours]
    ) as [any, any];
    expiredCount = result?.affectedRows ?? 0;
  } finally {
    conn.release();
  }

  await writeAuditEvent({
    tenant_id: scope.tenant_id,
    project_id: scope.project_id,
    event_type: 'PACKAGE_INVALIDATED',
    actor_id: 'system',
    actor_role: 'system',
    subject_ref: 'expireStaleTraces',
    detail: { expired_count: expiredCount, max_age_hours: maxAgeHours },
  });

  return expiredCount;
}
