class SerialQueue {
  constructor(name) {
    this.name    = name;
    this._queue  = [];
    this._active = false;
  }

  enqueue(fn) {
    return new Promise((resolve, reject) => {
      this._queue.push({ fn, resolve, reject });
      this._drain();
    });
  }

  _drain() {
    if (this._active || !this._queue.length) return;
    this._active = true;
    const { fn, resolve, reject } = this._queue.shift();
    Promise.resolve()
      .then(() => fn())
      .then(resolve, reject)
      .finally(() => { this._active = false; this._drain(); });
  }

  get depth()    { return this._queue.length; }          // waiting
  get running()  { return this._active ? 1 : 0; }        // active
  get total()    { return this.depth + this.running; }   // in-flight
}

