import { Request, Response, NextFunction } from 'express';
import jwt from 'jsonwebtoken';
import logger from '../../utils/logger';

const JWT_SECRET = process.env.JWT_SECRET;
const NODE_ENV = process.env.NODE_ENV || 'development';

if (!JWT_SECRET) {
    logger.error('[FATAL] JWT_SECRET environment variable is not set. Refusing to start with insecure defaults.');
    process.exit(1);
}

export interface AuthenticatedRequest extends Request {
    tenantId?: string;
    userId?: string;
}

export const authenticateToken = (req: AuthenticatedRequest, res: Response, next: NextFunction) => {
    const authHeader = req.headers['authorization'];
    const token = authHeader && authHeader.split(' ')[1];

    if (!token) {
        const clientIp = req.ip || req.socket.remoteAddress || 'unknown';
        logger.warn({ clientIp }, '[auth] missing auth token');
        return res.status(401).json({ error: 'Authentication token required' });
    }

    jwt.verify(token, JWT_SECRET as string, (err: any, user: any) => {
        if (err) {
            const clientIp = req.ip || req.socket.remoteAddress || 'unknown';
            logger.warn({ clientIp, err }, '[auth] token verification failed');
            // 403 for tampered/invalid signature; 401 for expired (client should re-authenticate)
            const status = err.name === 'JsonWebTokenError' ? 403 : 401;
            const message = status === 403 ? 'Token signature invalid' : 'Token expired';
            return res.status(status).json({ error: message });
        }
        // Accept both camelCase (legacy) and snake_case claims
        const tenantId = user.tenantId ?? user.tenant_id;
        const userId   = user.userId   ?? user.user_id ?? user.sub;
        if (!tenantId || !userId) {
            const clientIp = req.ip || req.socket.remoteAddress || 'unknown';
            logger.warn({ clientIp }, '[auth] malformed token claims');
            return res.status(401).json({ error: 'Malformed token claims' });
        }
        req.tenantId = tenantId;
        req.userId   = userId;
        // Expose full decoded claims so sub-systems (HLMM, DocCore) can read
        // project_id, role, roles, etc. without re-verifying the token.
        (req as any).jwtClaims = user;

        // Add X-Tenant-ID response header for debugging (non-production only)
        if (NODE_ENV !== 'production') {
            res.setHeader('X-Tenant-ID', tenantId);
        }

        next();
    });
};
