export interface MarkdownImportResult {
  doc_id: string;
  revision_id: string;
  snapshot_checksum: string;
  section_count: number;
  created_at: string;
}

const MAX_SECTION_KEY_LENGTH = 64;

function sha1(text: string): string {
  return createHash('sha1').update(text).digest('hex');
}

function slugify(input: string): string {
  const slug = input
    .toLowerCase()
    .replace(/[`*_~[\]()>#+.!?,:;'"\\\/]/g, ' ')
    .replace(/&/g, ' and ')
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '');
  return slug || 'section';
}

function classifySectionType(title: string, ordinal: number, isPreamble: boolean): string {
  if (isPreamble) return 'document_header';
  const normalized = title.toLowerCase();
  if (ordinal === 0 && normalized.includes('table of contents')) return 'table_of_contents';
  if (normalized.includes('table of contents')) return 'table_of_contents';
  if (normalized.includes('revision summary')) return 'revision_summary';
  if (normalized.includes('version history')) return 'version_history';
  if (normalized.includes('appendix')) return 'appendix';
  return 'body';
}

function buildSectionId(docId: string, sectionKey: string): string {
  return sha1(`${docId}:${sectionKey}`).slice(0, 40);
}

function normalizeSectionKey(baseKey: string, occurrence: number): string {
  const rawKey = occurrence === 1 ? baseKey : `${baseKey}-${occurrence}`;
  if (rawKey.length <= MAX_SECTION_KEY_LENGTH) return rawKey;

  const suffix = `-${sha1(rawKey).slice(0, 8)}`;
  const maxStemLength = MAX_SECTION_KEY_LENGTH - suffix.length;
  const stem = rawKey.slice(0, maxStemLength).replace(/-+$/g, '');
  return `${stem}${suffix}`;
}

export function splitMarkdownIntoSections(docId: string, markdown: string): ParsedMarkdownSection[] {
  const normalized = markdown.replace(/\r\n/g, '\n').trim();
  if (!normalized) {
    return [{
      section_id: buildSectionId(docId, 'document_body'),
      section_key: 'document_body',
      section_type: 'body',
      content_ref: '',
    }];
  }
