import { Response, NextFunction } from 'express';
import { AuthenticatedRequest } from './auth';
import db from "../../db/connection";

export interface VisibilityRequest extends AuthenticatedRequest {
    isSystemAdmin?: boolean;
    blindMode?: boolean;  // strips sensitive fields downstream
}

export const visibilityMiddleware = async (
    req: VisibilityRequest,
    res: Response,
    next: NextFunction
): Promise<void> => {
    if (!req.userId || process.env.SKIP_VISIBILITY_CHECK === 'true') { next(); return; }

    const conn = await db.getConnection();
    try {        const rows = await conn.query(
            'SELECT is_system_admin FROM users WHERE id = ? LIMIT 1',
            [req.userId]
        );
        if (rows.length && rows[0].is_system_admin) {
            req.isSystemAdmin = true;
            req.blindMode = true;
            // Bypass per-tenant filter by setting tenantId to wildcard sentinel
            req.tenantId = '__system_admin__';
        }
    } finally {
        conn.release();
    }
    next();
};

// Helper: strip sensitive fields from a row for blind-mode system admin
export const blindFilter = (row: Record<string, unknown>): Record<string, unknown> => {
    const SENSITIVE = new Set([
        'description',
        'settings',
        'content',
        'file_path',
        'file_content',
        'body',
    ]);
    return Object.fromEntries(
        Object.entries(row).filter(([k]) => !SENSITIVE.has(k))
    );
};
