export async function publishBrokerCommand(
  cmd: BrokerCommand
): Promise<'OK' | 'FAILED'> {
  return new Promise((resolve) => {
    let client: mqtt.MqttClient;
    try {
      client = getClient();
    } catch (err: any) {
      logger.warn(
        { correlation_id: cmd.correlationId, err },
        '[broker_command_publisher] Could not obtain MQTT client'
      );
      return resolve('FAILED');
    }

    const topic = `agenthub/control/${cmd.tenantId}/${cmd.agentId}/${cmd.command}`;
    const message = JSON.stringify({
      command: cmd.command,
      agent_id: cmd.agentId,
      tenant_id: cmd.tenantId,
      correlation_id: cmd.correlationId,
      payload: cmd.payload ?? {},
      issued_at: new Date().toISOString(),
    });

    client.publish(topic, message, { qos: 1 }, (err) => {
      if (err) {
        logger.warn(
          { topic, correlation_id: cmd.correlationId, err },
          '[broker_command_publisher] Publish failed'
        );
        return resolve('FAILED');
      }
      return resolve('OK');
    });
  });
}
