export function decrypt(encryptedText: string, ivHex: string): string {
    const iv = Buffer.from(ivHex, 'hex');
    const tag = Buffer.from(encryptedText.slice(-TAG_LENGTH * 2), 'hex');
    const content = encryptedText.slice(0, -TAG_LENGTH * 2);

    const decipher = crypto.createDecipheriv(ALGORITHM, MASTER_KEY, iv);
    decipher.setAuthTag(tag);

    let decrypted = decipher.update(content, 'hex', 'utf8');
    decrypted += decipher.final('utf8');

    return decrypted;
}

/**
 * Retrieves and decrypts a secret for the given tenant.
 * Falls back to the 'system' tenant if the tenant has no value for that key.
 * Returns null if no matching record is found.
 * The decrypted value exists only in-memory and is never persisted.
 */
export async function getSecret(tenantId: string, secretKey: string): Promise<string | null> {
    let conn;
    try {
        conn = await db.getConnection();
        let rows = await conn.query(
            'SELECT encrypted_value, iv FROM tenant_secrets WHERE tenant_id = ? AND secret_key = ?',
            [tenantId, secretKey]
        );
        if (rows.length === 0 && tenantId !== 'system') {
            rows = await conn.query(
                'SELECT encrypted_value, iv FROM tenant_secrets WHERE tenant_id = ? AND secret_key = ?',
                ['system', secretKey]
            );
        }
        if (rows.length === 0) return null;
        return decrypt(rows[0].encrypted_value, rows[0].iv);
    } finally {
        if (conn) conn.release();
    }
}

/**
 * Encrypts and upserts a secret for the given tenant.
 * Uses bitmask 4 (Write) semantics: INSERT ... ON DUPLICATE KEY UPDATE.
 */
export async function storeSecret(tenantId: string, secretKey: string, plainValue: string): Promise<void> {
    const { encryptedValue, iv } = encrypt(plainValue);
    let conn;
    try {
        conn = await db.getConnection();
        await conn.query(
            `INSERT INTO tenant_secrets (id, tenant_id, secret_key, encrypted_value, iv)
             VALUES (?, ?, ?, ?, ?)
             ON DUPLICATE KEY UPDATE encrypted_value = VALUES(encrypted_value), iv = VALUES(iv), updated_at = NOW()`,
            [uuidv4(), tenantId, secretKey, encryptedValue, iv]
        );
    } finally {
        if (conn) conn.release();
    }
}
