  const [primary, ...secondary] = brokerUrls;
  PRIMARY_BROKER_CLIENT = startBridgeForBroker(redis, primary.url, primary.label, false);
  for (const { url, label } of secondary) {
    startBridgeForBroker(redis, url, label, true);
  }
}
