/**
 * Deterministic SHA-256 checksum of the composition inputs.
 * Entries are sorted by stable JSON serialisation to guarantee determinism.
 */
function computeSnapshotChecksum(inputs: CompositionInput): string {
  // Flatten to a stable array of the content being composed
  const parts = (inputs.entries ?? []).map((e) => ({
    ordinal: e.ordinal,
    checksum: e.checksum,
    content_md: e.content_md,
  }));
  // Sort by ordinal for stability; fall back to JSON comparison
  parts.sort((a, b) => a.ordinal - b.ordinal || JSON.stringify(a).localeCompare(JSON.stringify(b)));
  const content = JSON.stringify({ revision: inputs.revision?.document_revision_id, parts });
  return createHash('sha256').update(content).digest('hex').substring(0, 16);
}

