export function namespaceValidator(id: string): boolean {
  // Global Naming Constraints:
  // 1. Lowercase Only: All IDs and namespaces must be strictly lowercase.
  // 2. Word Separators: Use underscores (_) for word separation (e.g., ah_eng01, dashboard_ui). No dashes (-) are allowed.
  // 3. Hierarchical Separators: Use periods (.) strictly to delimit hierarchy levels (e.g., project.req.task.test).
  // 4. Descriptive Naming: The final segment of an ID should be a condensed descriptive name (e.g., req_auth, bug_login_crash).

  // Regex:
  // ^                         - Start of string
  // [a-z0-9_]+                - First segment: lowercase letters, numbers, underscores (no dashes)
  // (?:\.[a-z0-9_]+)*        - Optional subsequent segments, each prefixed by a period,
  //                             and containing lowercase letters, numbers, underscores.
  // $                         - End of string
  const regex = /^[a-z0-9_]+(?:\.[a-z0-9_]+)*$/;
  return regex.test(id);
}
