  agentId: string,
  tenantId: string,
  actorUserId: string,
  assignmentType: 'TASK' | 'TEST' | 'BUG',
  workItemId: string,
  notes?: string
): Promise<LifecycleResult> {
  const correlationId = randomUUID();
  const requestId = await createActionRequest({
    tenantId, agentId, actorUserId, actionType: `ASSIGN_${assignmentType}`, correlationId,
    requestPayload: { work_item_id: workItemId, notes },
  });

  const result = await applyAssignment({ agentId, tenantId, actorUserId, correlationId, assignmentType, workItemId, notes });

  if (result === 'OK') {
    await updateActionRequest({ requestId, status: 'COMPLETED', resolvedAt: true, tenantId });
    return { ok: true, requestId, correlationId };
  }
  const codeMap: Record<string, string> = {
    'NOT_FOUND': 'WORK_ITEM_NOT_FOUND',
    'TYPE_MISMATCH': 'INVALID_ASSIGNMENT_TYPE',
    'POLICY_DENIED': 'ACTION_NOT_ALLOWED',
    'AGENT_NOT_FOUND': 'AGENT_NOT_FOUND',
  };
  const errorCode = codeMap[result] ?? 'ACTION_NOT_ALLOWED';
  await updateActionRequest({ requestId, status: 'FAILED', outcomeCode: errorCode, resolvedAt: true, tenantId });
  return { ok: false, errorCode, message: `Assignment failed: ${result}` };
}

