export async function requestAgentStart(
  agentId: string,
  tenantId: string,
  actorUserId: string
): Promise<LifecycleResult> {
  const correlationId = randomUUID();
  const policy = await computeActionPolicy(agentId, tenantId, correlationId);
  if (!policy) return { ok: false, errorCode: 'AGENT_NOT_FOUND', message: 'Agent not found in tenant scope' };
  if (!policy.actions.START?.enabled)
    return { ok: false, errorCode: 'ACTION_NOT_ALLOWED', message: policy.actions.START?.reason ?? 'Start not allowed in current state' };

  const requestId = await createActionRequest({
    tenantId, agentId, actorUserId, actionType: 'START', correlationId,
  });

  const dispatch = await publishBrokerCommand({ command: 'AGENT_START', agentId, tenantId, correlationId });
  if (dispatch === 'FAILED') {
    await updateActionRequest({ requestId, status: 'FAILED', outcomeCode: 'DOWNSTREAM_DISPATCH_FAILED', tenantId });
    return { ok: false, errorCode: 'DOWNSTREAM_DISPATCH_FAILED', message: 'Broker dispatch failed' };
  }
  await updateActionRequest({ requestId, status: 'DISPATCHED', dispatchedAt: true, tenantId });
  return { ok: true, requestId, correlationId };
}

